import java.util.*;

public class Solution {
    public boolean isPossible(int[] target) {
        PriorityQueue<Integer> pq = new PriorityQueue<>((a, b) -> b - a);
        long sum = 0;
        for (int num : target) {
            sum += num;
            pq.offer(num);
        }
        while (pq.peek() != 1) {
            int num = pq.poll();
            sum -= num;
            if (sum <= 0 || sum >= num) return false;
            num %= sum;
            if (num == 0) num = sum;
            pq.offer(num);
            sum += num;
        }
        return true;
    }
}
```
